<template>
  <div class="w-full h-full flex">
    <!-- ./Modal trigger -->
    <transition
      name="custom"
      enter-active-class="animate__animated animate__bounceInDown"
      leave-active-class="animate__animated animate__bounceOutUp"
    >
      <!-- Modal -->
      <div
        v-if="showModal"
        class="
          w-11/12
          lg:w-full
          max-w-xl
          z-20
          mx-auto
          bg-white
          flex flex-col
          relative
          self-center
          shadow-2xl
          rounded-md
        "
      >
        <div
          class="p-6 border-b-4 border-gray-200 text-lg font-bold text-red-600"
        >
          🚧，暂未开放
        </div>
        <div class="flex flex-col py-6 px-8 space-y-5">
          <input
            type="password"
            placeholder="请输入密码"
            v-model="password"
            class="
              px-2
              py-2
              border-2
              rounded-md
              border-gray-200
              focus:outline-none
              focus:ring-1 focus:ring-pink-300
              focus:border-transparent
            "
          />
          <button
            @click.stop="submit"
            class="
              w-full
              py-3
              bg-red-400
              text-white
              rounded-md
              text-sm
              focus:outline-none
              focus:ring-2 focus:ring-pink-500
              focus:border-transparent
              shadow-lg
            "
          >
            验证访问
          </button>
        </div>
      </div>
      <!-- ./Modal -->
    </transition>
  </div>
</template>
<script>
/**
 * 遮罩
 * <transition
      name="custom"
      enter-active-class="animate__animated animate__fadeIn"
      leave-active-class="animate__animated animate__fadeOut"
    >
      <!-- Overlay -->
      <div
        v-if="showModal"
        class="
          bg-gray-700 bg-opacity-50
          fixed
          bottom-0
          left-0
          w-full
          h-full
          transition
          duration-500
          ease-in-out
          transfom
          z-10
        "
      ></div>
      <!-- ./Overlay -->
    </transition>
 */
export default {
  name: "Secret",
  data() {
    return {
      ref: null,
      password: "",
      redirect: null,
      showModal: false,
    };
  },
  watch: {
    $route: {
      handler: function (route) {
        this.redirect = route.query && route.query.redirect;
      },
      immediate: true,
    },
  },
  methods: {
    submit() {
      try {
        this.$store.dispatch("setSIG", this.password);
        this.$router.push(this.redirect);
      } catch (err) {
        alert("密码错误");
      }
    },
  },
  mounted() {
    this.showModal = true;
  },
};
</script>
